Correct Example:
from collections import Counter
import re

def count_medals(medals):
 result = {'Gold': 0, 'Silver': 0, 'Bronze': 0}
 if medals != 0:
 found = re.findall(r'Gold|Bronze|Silver', medals)
 counts = dict(Counter(found))
 result.update(counts)
 return result

