from collections import Counter

token_sets = {
 'cluster_1': {'apple', 'banana'},
 'cluster_2': {'apple', 'cherry'},
 'cluster_3': {'banana', 'date'}
}
max_occur = 1

token_counts = Counter()
for tokens in token_sets.values():
 token_counts.update(tokens)

distinctive = {}
for cluster, tokens in token_sets.items():
 kept = {token for token in tokens if token_counts[token] <= max_occur}
 if kept:
 distinctive[cluster] = kept

kept = set()
