WITH people AS (
SELECT 'Ava' AS name, 17 AS age
UNION ALL
SELECT 'Ben', 22
)
SELECT name, CASE WHEN age >= 18 THEN 'Adult' ELSE 'Minor' END FROM people;

WITH items AS (
SELECT 'SKU-2048-RED' AS code
UNION ALL
SELECT 'ITEM-55-BLUE'
)
SELECT code, SUBSTR(code,INSTR(code,'-')+1) FROM items;

WITH athletes AS (
SELECT '  Ava  ' AS name
UNION ALL
SELECT ' Ben'
)
SELECT TRIM(name) FROM athletes;

WITH companies AS (
SELECT 'Acme Ltd.' AS name
UNION ALL
SELECT 'Northwind Ltd.'
)
SELECT REPLACE(name,'Ltd.','Limited') FROM companies;

