import pandas as pd

df = pd.DataFrame({
 'store': ['A', 'A', 'B', 'B'],
 'revenue': [100, 250, 80, 120]
})

summary = df.groupby('store').agg(
 total_revenue=('revenue', 'sum'),
 revenue_range=('revenue', lambda x: x.max() - x.min())
)

print(summary)

