 SELECT date('2023-01-01') AS clean_date
)
SELECT
 strftime('%m', clean_date) || '-' ||
 substr('JANFEBMARAPRMAYJUNJULAUGSEPOCTNOVDEC',
 (cast(strftime('%m', clean_date) as integer) - 1) * 3 + 1,
 3
 ) AS formatted_month
FROM inner_query;

